// Solution
int Solution::findFirstDuplicate(vector<int>& nums) {
    int seen[10001] = {0};
    for (int num : nums) {
        if (seen[num]) {
            return num;
        } else {
            seen[num] = 1;
        }
    }
    return -1;
}

